from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            # Return a simple nationality adjective for smoother combination
            low_obj = obj.lower()
            mapping = {
                "united states": "American",
                "usa": "American",
                "united states of america": "American",
                "canada": "Canadian",
                "russia": "Russian",
                "japan": "Japanese",
                "china": "Chinese",
                "britain": "British",
                "united kingdom": "British",
                "france": "French",
                "germany": "German",
                # add more as needed
            }
            # Remove possible leading "the "
            if low_obj.startswith("the "):
                low_obj = low_obj[4:]
            return mapping.get(low_obj, obj.title())
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            # Return a simple status adjective
            low = obj.lower()
            if low == "retired":
                return "retired"
            return low
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"was operated by {obj}"
        if p == "commander":
            # For mission subjects, express role succinctly
            if subj.lower().startswith("apollo"):
                return f"was commanded by {obj}"
            return f"was the commander, {obj}"
        if p == "backuppilot":
            # Express backup pilot role
            return f"had {obj} as backup pilot"
        if p == "crewmembers":
            # Express crew membership from astronaut perspective
            return f"{obj} was a crew member of {subj}"
        if p == "dateofretirement":
            # Handle retirement date phrasing
            # Remove surrounding quotes if present
            obj_clean = obj.strip().strip('"')
            return f"retired in {obj_clean}"
        if p == "leader":
            # Subject is an entity, object is a person
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        # No special handling; treat all predicates uniformly
        subject_phrase = subj
        remaining_items = items

        raw_desc = [phrase(subj, t.predicate, t.object) for t in remaining_items]

        # Separate simple adjectives (no spaces) from full clauses
        adjectives = [d for d in raw_desc if ' ' not in d and d]
        clauses = [d for d in raw_desc if d not in adjectives]

        parts = []
        if adjectives:
            parts.append(f"is {' '.join(adjectives)}")
        parts.extend(clauses)

        if not parts:
            sentences.append(f"{subject_phrase}.")
            continue
        if len(parts) == 1:
            sent = f"{subject_phrase} {parts[0]}."
        elif len(parts) == 2:
            sent = f"{subject_phrase} {parts[0]} and {parts[1]}."
        else:
            body = ", ".join(parts[:-1])
            sent = f"{subject_phrase} {body}, and {parts[-1]}."
        sentences.append(sent)

    # Combine sentences for different subjects
    return " ".join(sentences)

# EVOLVE-BLOCK-END
